import{_ as e,o as r,c as o,ag as a}from"./chunks/framework.6MCaaFDc.js";const m=JSON.parse('{"title":"E-Communication","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/e-communication.md","filePath":"theory/networks/e-communication.md"}'),n={name:"theory/networks/e-communication.md"};function i(s,t,d,l,c,h){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="e-communication" tabindex="-1">E-Communication <a class="header-anchor" href="#e-communication" aria-label="Permalink to &quot;E-Communication&quot;">​</a></h1><p>Electronic communication has replaced letters, fax machines, and phone trees. Email, instant messaging, video conferencing, and social media all rely on the same underlying networks — but they come with unique protocols, etiquette requirements, and threats.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10–11</p><p>E-communication is introduced at Grade 10 (email basics, netiquette, threats) and extended at Grade 11 (VoIP, RSS, protocols).</p></div><hr><h2 id="forms-of-electronic-communication" tabindex="-1">Forms of Electronic Communication <a class="header-anchor" href="#forms-of-electronic-communication" aria-label="Permalink to &quot;Forms of Electronic Communication&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Email</strong></td><td>Asynchronous text/file communication via mail servers</td><td>Gmail, Outlook</td></tr><tr><td><strong>Instant messaging (IM)</strong></td><td>Real-time text chat</td><td>WhatsApp, Telegram, Teams</td></tr><tr><td><strong>VoIP</strong></td><td>Voice (and video) calls over the internet</td><td>Zoom, Teams, WhatsApp calls, Skype</td></tr><tr><td><strong>Social media</strong></td><td>Sharing content, updates, and communication</td><td>Facebook, Instagram, X (Twitter)</td></tr><tr><td><strong>RSS feeds</strong></td><td>Subscribing to website updates</td><td>News aggregators, podcasts</td></tr><tr><td><strong>Discussion forums</strong></td><td>Asynchronous threaded discussions</td><td>Reddit, Stack Overflow</td></tr><tr><td><strong>Blog / vlog</strong></td><td>Publishing written or video content</td><td>WordPress, YouTube</td></tr><tr><td><strong>Video conferencing</strong></td><td>Real-time multi-party video calls</td><td>Zoom, Google Meet, Teams</td></tr></tbody></table><hr><h2 id="email-—-how-it-works" tabindex="-1">Email — How it Works <a class="header-anchor" href="#email-—-how-it-works" aria-label="Permalink to &quot;Email — How it Works&quot;">​</a></h2><p>Email relies on three protocols:</p><table tabindex="0"><thead><tr><th>Protocol</th><th>Full Name</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>SMTP</strong></td><td>Simple Mail Transfer Protocol</td><td><strong>Sending</strong> email (port 25/587)</td></tr><tr><td><strong>POP3</strong></td><td>Post Office Protocol v3</td><td><strong>Downloading</strong> email from server (port 110) — deletes from server</td></tr><tr><td><strong>IMAP</strong></td><td>Internet Message Access Protocol</td><td><strong>Accessing</strong> email on server (port 143) — stays on server</td></tr></tbody></table><h3 id="smtp-process-sending" tabindex="-1">SMTP Process (sending): <a class="header-anchor" href="#smtp-process-sending" aria-label="Permalink to &quot;SMTP Process (sending):&quot;">​</a></h3><ol><li>You compose and send an email in your email client</li><li>Client connects to your <strong>outgoing mail server (SMTP)</strong></li><li>SMTP server looks up the recipient domain&#39;s <strong>MX record</strong> via DNS</li><li>Connects to the recipient&#39;s mail server and delivers the message</li><li>Message sits in the recipient&#39;s mailbox until they download/view it</li></ol><h3 id="pop3-vs-imap" tabindex="-1">POP3 vs IMAP <a class="header-anchor" href="#pop3-vs-imap" aria-label="Permalink to &quot;POP3 vs IMAP&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>POP3</th><th>IMAP</th></tr></thead><tbody><tr><td>Email stored</td><td>Downloaded to device</td><td>Stays on server</td></tr><tr><td>Multiple devices</td><td>Poor — one device at a time</td><td>Excellent — syncs across all devices</td></tr><tr><td>Offline access</td><td>Yes (after download)</td><td>Limited (needs connection to view)</td></tr><tr><td>Storage</td><td>Local device</td><td>Server storage</td></tr><tr><td>Best for</td><td>Single device</td><td>Multiple devices</td></tr></tbody></table><hr><h2 id="email-best-practices" tabindex="-1">Email Best Practices <a class="header-anchor" href="#email-best-practices" aria-label="Permalink to &quot;Email Best Practices&quot;">​</a></h2><h3 id="structure-of-a-professional-email" tabindex="-1">Structure of a professional email: <a class="header-anchor" href="#structure-of-a-professional-email" aria-label="Permalink to &quot;Structure of a professional email:&quot;">​</a></h3><ul><li><strong>To</strong> — primary recipient(s)</li><li><strong>CC</strong> (Carbon Copy) — receives a copy; all recipients can see this</li><li><strong>BCC</strong> (Blind Carbon Copy) — receives a copy; other recipients cannot see BCC list</li><li><strong>Subject</strong> — clear, specific summary of the email topic</li><li><strong>Body</strong> — professional, clear language</li><li><strong>Signature</strong> — name, position, contact details</li></ul><h3 id="attachment-guidelines" tabindex="-1">Attachment guidelines: <a class="header-anchor" href="#attachment-guidelines" aria-label="Permalink to &quot;Attachment guidelines:&quot;">​</a></h3><ul><li>Keep file sizes small — compress large attachments</li><li>Warn recipient before sending large files</li><li>Never open unexpected attachments from unknown senders</li></ul><hr><h2 id="netiquette" tabindex="-1">Netiquette <a class="header-anchor" href="#netiquette" aria-label="Permalink to &quot;Netiquette&quot;">​</a></h2><p><strong>Netiquette</strong> (internet etiquette) — rules for respectful and appropriate online communication.</p><table tabindex="0"><thead><tr><th>Rule</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>No caps lock</strong></td><td>TYPING IN ALL CAPS = shouting — considered rude</td></tr><tr><td><strong>Use clear subject lines</strong></td><td>Helps recipient prioritise and find email later</td></tr><tr><td><strong>Reply promptly</strong></td><td>Respond within 24–48 hours for professional email</td></tr><tr><td><strong>Don&#39;t forward without permission</strong></td><td>Private emails should not be forwarded</td></tr><tr><td><strong>Proofread before sending</strong></td><td>Check spelling, tone, and correct recipients</td></tr><tr><td><strong>Don&#39;t CC unnecessarily</strong></td><td>Only CC people who need to be informed</td></tr><tr><td><strong>Respect others&#39; time</strong></td><td>Be concise — don&#39;t send unnecessarily long emails</td></tr><tr><td><strong>No spam</strong></td><td>Don&#39;t send unsolicited bulk email</td></tr><tr><td><strong>Cite sources</strong></td><td>If sharing information, credit the original author</td></tr><tr><td><strong>Be respectful</strong></td><td>Online anonymity doesn&#39;t excuse rude behaviour</td></tr></tbody></table><hr><h2 id="voip-—-voice-over-internet-protocol" tabindex="-1">VoIP — Voice over Internet Protocol <a class="header-anchor" href="#voip-—-voice-over-internet-protocol" aria-label="Permalink to &quot;VoIP — Voice over Internet Protocol&quot;">​</a></h2><p><strong>VoIP</strong> converts voice (and video) into digital data packets and transmits them over the internet.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Detail</th></tr></thead><tbody><tr><td>How it works</td><td>Audio → digitised → compressed → sent as data packets → reassembled</td></tr><tr><td>Advantage</td><td>Cheap or free calls anywhere in the world</td></tr><tr><td>Disadvantage</td><td>Quality depends on internet connection; latency can cause echo</td></tr><tr><td>Examples</td><td>Zoom, Microsoft Teams, WhatsApp calls, Skype, Google Meet</td></tr></tbody></table><p><strong>VoIP vs Traditional phone:</strong></p><table tabindex="0"><thead><tr><th></th><th>VoIP</th><th>Traditional</th></tr></thead><tbody><tr><td>Cost</td><td>Low (uses existing internet)</td><td>Higher (phone network charges)</td></tr><tr><td>International calls</td><td>Cheap/free</td><td>Expensive</td></tr><tr><td>Quality</td><td>Varies with internet</td><td>Consistent</td></tr><tr><td>Infrastructure needed</td><td>Internet connection</td><td>Phone line</td></tr></tbody></table><hr><h2 id="rss-—-really-simple-syndication" tabindex="-1">RSS — Really Simple Syndication <a class="header-anchor" href="#rss-—-really-simple-syndication" aria-label="Permalink to &quot;RSS — Really Simple Syndication&quot;">​</a></h2><p><strong>RSS</strong> is a format that allows users to subscribe to updates from websites and have new content delivered automatically.</p><ul><li>Website publishes an <strong>RSS feed</strong> (XML file) that updates when new content is added</li><li>User subscribes in an <strong>RSS reader</strong> (aggregator)</li><li>New articles, podcasts, or news items appear in the reader automatically</li><li>No need to visit each website individually</li></ul><p><strong>Examples:</strong> news aggregators, podcast subscriptions, blog updates</p><hr><h2 id="email-threats" tabindex="-1">Email Threats <a class="header-anchor" href="#email-threats" aria-label="Permalink to &quot;Email Threats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Threat</th><th>Description</th></tr></thead><tbody><tr><td><strong>Spam</strong></td><td>Unsolicited bulk email — usually advertising or malicious</td></tr><tr><td><strong>Phishing</strong></td><td>Fake email pretending to be a trusted organisation to steal credentials</td></tr><tr><td><strong>Spear phishing</strong></td><td>Targeted phishing aimed at a specific person (more convincing)</td></tr><tr><td><strong>Vishing</strong></td><td>Voice phishing — scam phone calls</td></tr><tr><td><strong>Smishing</strong></td><td>SMS phishing — fake text messages</td></tr><tr><td><strong>Email spoofing</strong></td><td>Forging the sender address to appear legitimate</td></tr><tr><td><strong>Malicious attachments</strong></td><td>Email attachments containing malware</td></tr><tr><td><strong>Malicious links</strong></td><td>Links that redirect to fake or infected websites</td></tr></tbody></table><h3 id="identifying-phishing-emails" tabindex="-1">Identifying phishing emails: <a class="header-anchor" href="#identifying-phishing-emails" aria-label="Permalink to &quot;Identifying phishing emails:&quot;">​</a></h3><ul><li>Urgent or threatening language (&quot;Your account will be suspended!&quot;)</li><li>Sender email address doesn&#39;t match claimed organisation</li><li>Hover over links — URL doesn&#39;t match display text</li><li>Generic greeting (&quot;Dear Customer&quot; instead of your name)</li><li>Requests for passwords, PINs, or banking details</li><li>Grammar and spelling errors</li></ul><hr><h2 id="protection-against-email-threats" tabindex="-1">Protection Against Email Threats <a class="header-anchor" href="#protection-against-email-threats" aria-label="Permalink to &quot;Protection Against Email Threats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Measure</th><th>How it helps</th></tr></thead><tbody><tr><td><strong>Spam filter</strong></td><td>Automatically moves suspicious email to junk/spam</td></tr><tr><td><strong>Antivirus</strong></td><td>Scans attachments before opening</td></tr><tr><td><strong>2FA on email accounts</strong></td><td>Even if password is stolen, account can&#39;t be accessed</td></tr><tr><td><strong>Don&#39;t click unknown links</strong></td><td>Visit websites directly by typing the URL</td></tr><tr><td><strong>Verify requests</strong></td><td>Phone the organisation directly to confirm requests</td></tr><tr><td><strong>Keep software updated</strong></td><td>Patches vulnerabilities exploited by malware</td></tr><tr><td><strong>Check sender address</strong></td><td>Look at actual email address, not just display name</td></tr></tbody></table><hr><h2 id="online-communication-and-privacy" tabindex="-1">Online Communication and Privacy <a class="header-anchor" href="#online-communication-and-privacy" aria-label="Permalink to &quot;Online Communication and Privacy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Consideration</th></tr></thead><tbody><tr><td><strong>Digital footprint</strong></td><td>All online activity leaves traces — emails, posts, chats</td></tr><tr><td><strong>Cloud storage of messages</strong></td><td>Emails on cloud servers can be accessed by provider</td></tr><tr><td><strong>End-to-end encryption</strong></td><td>WhatsApp, Signal — only sender/receiver can read</td></tr><tr><td><strong>Data retention</strong></td><td>Many services keep your messages for years</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Email</strong></td><td>Electronic message sent via mail servers</td></tr><tr><td><strong>SMTP</strong></td><td>Protocol for sending email</td></tr><tr><td><strong>POP3</strong></td><td>Protocol for downloading email (removes from server)</td></tr><tr><td><strong>IMAP</strong></td><td>Protocol for accessing email while keeping it on server</td></tr><tr><td><strong>CC</strong></td><td>Carbon copy — sends a copy; visible to all recipients</td></tr><tr><td><strong>BCC</strong></td><td>Blind carbon copy — hidden from other recipients</td></tr><tr><td><strong>VoIP</strong></td><td>Voice over IP — voice/video calls over the internet</td></tr><tr><td><strong>RSS</strong></td><td>Format for subscribing to website content updates</td></tr><tr><td><strong>Netiquette</strong></td><td>Etiquette rules for online communication</td></tr><tr><td><strong>Spam</strong></td><td>Unsolicited bulk email</td></tr><tr><td><strong>Phishing</strong></td><td>Fake emails designed to steal credentials</td></tr><tr><td><strong>Spoofing</strong></td><td>Forging sender identity to appear legitimate</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Explain the difference between POP3 and IMAP&quot;</strong> — POP3 downloads email to one device and deletes from server; IMAP keeps email on the server and syncs across multiple devices</p></li><li><p><strong>&quot;What is VoIP? Give ONE advantage and ONE disadvantage&quot;</strong> — Voice over IP — converts voice to data packets sent over internet; advantage: cheap/free international calls; disadvantage: quality depends on internet connection</p></li><li><p><strong>&quot;Give FOUR rules of netiquette&quot;</strong> — don&#39;t type in all caps; use clear subject lines; don&#39;t forward without permission; reply promptly; be concise</p></li><li><p><strong>&quot;How can you identify a phishing email?&quot;</strong> — urgent language; sender address doesn&#39;t match; hover over links to see real URL; generic greeting; requests for passwords/banking details; spelling errors</p></li><li><p><strong>&quot;What is the difference between phishing and spear phishing?&quot;</strong> — phishing is a mass email to many people; spear phishing is targeted at a specific individual and is more convincing as it uses personal details</p></li></ol></div>',52)])])}const u=e(n,[["render",i]]);export{m as __pageData,u as default};
